3	const readStdin = async (): Promise<string> => {
4	  const chunks: Buffer[] = [];
5	  for await (const chunk of process.stdin) {
6	    chunks.push(chunk as Buffer);
7	  }
8	  return Buffer.concat(chunks).toString("utf8");
9	};
10	
11	const main = async (): Promise<void> => {
12	  try {
13	    const input = JSON.parse(await readStdin());
14	    const output = runScenario(input);
15	    process.stdout.write(JSON.stringify(output) + "\n");
16	  } catch (error) {
17	    const message = error instanceof Error ? error.message : String(error);
18	    process.stderr.write(message + "\n");
19	    process.exit(1);
20	  }
21	};
22	
23	void main();
